object AnalyticsPlatform {
  private val spark = SparkSession.builder()
    .appName("UserQueryAnalyticsPlatform")
    .config("spark.sql.adaptive.enabled", "true")
    .config("spark.sql.adaptive.coalescePartitions.enabled", "true")
    .getOrCreate()
  
  private val queryCache = new ConcurrentHashMap[String, Long]()
  
  def executeUserQuery(query: String): QueryResult = {
    val startTime = System.currentTimeMillis()
    
    try {
      val result = spark.sql(query)
      val executionTime = System.currentTimeMillis() - startTime
      
      // Cache query results for performance optimization
      queryCache.put(query, executionTime)
      
      QueryResult(success = true, data = Some(result), executionTime = executionTime)
    } catch {
      case e: Exception =>
        val executionTime = System.currentTimeMillis() - startTime
        QueryResult(success = false, error = Some(e.getMessage), executionTime = executionTime)
    }
  }
  
  def getQueryCacheStats: Map[String, Long] = {
    queryCache.asScala.toMap
  }
  
  def getSparkSession: SparkSession = spark
  
  def close(): Unit = {
    spark.stop()
  }
}

object QueryExecutor {
  def execute(query: String): QueryResult = {
